static ge::graphStatus InferShape(gert::InferShapeContext *context) {
    // Fix: GetInputShape returns const gert::StorageShape*
    const gert::StorageShape *xShape = context->GetInputShape(0);
    const gert::Shape &originShape = xShape->GetOriginShape();

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int kernel_size = attrs->GetAttrPointer<int>(0)[0];
    int stride = attrs->GetAttrPointer<int>(1)[0];
    int padding = attrs->GetAttrPointer<int>(2)[0];

    uint32_t depthIn = originShape.GetDim(2);
    uint32_t heightIn = originShape.GetDim(3);
